import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { v4 as uuidv4 } from 'uuid';
import { FinancialsService } from '../../services/financials.service';

@Component({
  selector: 'app-financials-edit',
  templateUrl: './financials-edit.component.html'
})
export class FinancialsEditComponent implements OnInit {
  form: FormGroup;
  editingId?: string;

  constructor(private fb: FormBuilder, private route: ActivatedRoute, private router: Router, private svc: FinancialsService) {
    this.form = this.fb.group({
      title: ['', Validators.required],
      type: ['bill', Validators.required],
      amount: ['', Validators.required],
      currency: ['USD'],
      dueDate: [''],
      recurring: [false],
      notes: ['']
    });
  }

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (id && id !== 'new') {
      this.editingId = id;
      this.svc.list$.subscribe(list => {
        const item = list.find(i => i.id === id);
        if (item) this.form.patchValue(item as any);
      });
    }
  }

  save() {
    if (this.form.invalid) return;
    const payload = this.form.value;
    if (this.editingId) {
      this.svc.update(this.editingId, payload);
    } else {
      this.svc.add({ id: uuidv4(), ...payload, createdAt: new Date().toISOString() } as any);
    }
    this.router.navigate(['/financials']);
  }
}
<div class="card">
  <h2 *ngIf="editingId; else newTitle">Edit Financial Record</h2>
  <ng-template #newTitle><h2>New Financial Record</h2></ng-template>

  <form [formGroup]="form" (ngSubmit)="save()">
    <div class="form-row">
      <input class="input" placeholder="Title" formControlName="title" required />
      <select class="input" formControlName="type">
        <option value="bill">Bill</option>
        <option value="subscription">Subscription</option>
        <option value="expense">Expense</option>
        <option value="income">Income</option>
      </select>
    </div>
    <div class="form-row" style="margin-top:8px">
      <input class="input" placeholder="Amount" formControlName="amount" type="number" required />
      <input class="input" placeholder="Currency" formControlName="currency" />
    </div>
    <div class="form-row" style="margin-top:8px">
      <input class="input" placeholder="Due Date" formControlName="dueDate" type="date" />
      <label style="margin-left:8px">
        <input type="checkbox" formControlName="recurring" /> Recurring
      </label>
    </div>
    <div style="margin-top:8px">
      <textarea class="input" placeholder="Notes" formControlName="notes" rows="3"></textarea>
    </div>

    <div style="margin-top:12px">
      <button class="btn" type="submit">Save</button>
      <a routerLink="/financials" style="margin-left:8px">Cancel</a>
    </div>
  </form>
</div>
